// TestIntegration_ScriptHarness_NoOp_ClassifiedAsNoChanges verifies that a
// directive that makes no filesystem or git changes but writes the required
// rationale results in outcome=no_changes and the bead remains open below the
// adjudication threshold.
func TestIntegration_ScriptHarness_NoOp_ClassifiedAsNoChanges(t *testing.T) {
	skipIntegrationInShort(t)
	projectRoot, _ := newScriptHarnessRepo(t, 1)
	ddxDir := filepath.Join(projectRoot, ddxroot.DirName)
	const beadID = "ddx-int-0001"

	commitsBefore := gitCommitCount(t, projectRoot, "HEAD")

	dirFile := filepath.Join(t.TempDir(), "directive.txt")
	writeDirectiveFile(t, dirFile, []string{
		"run mkdir -p .ddx/executions/$DDX_ATTEMPT_ID && printf 'already satisfied in base' > .ddx/executions/$DDX_ATTEMPT_ID/no_changes_rationale.txt",
	})

	store := makeLoopStore(t, ddxDir)
	worker := &ExecuteBeadWorker{
		Store:    store,
		Executor: scriptHarnessExecutor(t, projectRoot, dirFile),
	}

	cfgOpts := config.TestLoopConfigOpts{
		Assignee:                "integration-worker",
		MaxNoChangesBeforeClose: 3, // explicit threshold so test is readable
	}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once: true,
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	assert.Equal(t, 1, result.Attempts)
	assert.Equal(t, 0, result.Successes)
	assert.Equal(t, 1, result.Failures)
	assert.Equal(t, ExecuteBeadStatusNoChanges, result.LastFailureStatus)

	// Bead must still be open.
	beadStore := bead.NewStore(ddxDir)
	got, err := beadStore.Get(context.Background(), beadID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, got.Status, "bead should remain open on first no_changes")

	// Main branch must not have grown (tracker commit aside — tracker commits
	// are made before the worktree; the landing step only advances on real changes).
	commitsAfter := gitCommitCount(t, projectRoot, "HEAD")
	// Allow for the tracker commit (CommitTracker runs before the worktree add).
	// What must NOT happen: a merge commit landing the no-op.
	// The tracker may add 1, but the iteration itself adds 0.
	assert.LessOrEqual(t, commitsAfter-commitsBefore, 1,
		"no iteration commit should land when no changes were made")
}

// TestIntegration_WorkInterruptDuringScriptHarnessNoChangesDoesNotDirtyTracker
// reproduces the production failure behind ddx-7000e777 with the real
// work stack: temp git repo, JSONL bead store, execute-bead worktree,
// and script harness. The script does not observe context cancellation while it
// sleeps, so the worker context is cancelled mid-attempt and the no_changes-like
// result returns after cancellation. That must only release the claim; it must
// not record terminal/no_changes/loop-error queue noise.
func TestIntegration_WorkInterruptDuringScriptHarnessNoChangesDoesNotDirtyTracker(t *testing.T) {
	skipIntegrationInShort(t)
	projectRoot, _ := newScriptHarnessRepo(t, 1)
	ddxDir := filepath.Join(projectRoot, ddxroot.DirName)
	const beadID = "ddx-int-0001"

	dirFile := filepath.Join(t.TempDir(), "directive.txt")
	writeDirectiveFile(t, dirFile, []string{
		"sleep-ms 1000",
		"no-op",
	})

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	store := makeLoopStore(t, ddxDir)
	baseExecutor := scriptHarnessExecutor(t, projectRoot, dirFile)
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			time.AfterFunc(50*time.Millisecond, cancel)
			return baseExecutor(ctx, beadID)
		}),
	}

	done := make(chan struct {
		result *ExecuteBeadLoopResult
		err    error
	}, 1)
	go func() {
		cfgOpts := config.TestLoopConfigOpts{Assignee: "integration-worker"}
		rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
		result, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{Once: true})
		done <- struct {
			result *ExecuteBeadLoopResult
			err    error
		}{result: result, err: err}
	}()

	leaseStore, ok := store.(*bead.Store)
	require.True(t, ok, "integration store must expose claim leases")
	require.Eventually(t, func() bool {
		lease, found, err := leaseStore.ClaimLease(beadID)
		return err == nil && found && lease.Owner == "integration-worker"
	}, 5*time.Second, 10*time.Millisecond, "worker did not acquire the claim lease")

	var out struct {
		result *ExecuteBeadLoopResult
		err    error
	}
	select {
	case out = <-done:
	case <-time.After(10 * time.Second):
		t.Fatal("worker did not return after cancellation")
	}
	require.ErrorIs(t, out.err, context.Canceled)
	require.NotNil(t, out.result)
	require.Len(t, out.result.Results, 1)
	assert.True(t, out.result.Results[0].Disrupted)
	assert.Equal(t, "context_canceled", out.result.Results[0].DisruptionReason)

	got, err := store.Get(context.Background(), beadID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, got.Status)
	assert.Empty(t, got.Owner)
	assert.NotContains(t, got.Labels, NoChangesLabelUnjustified)
	assert.NotContains(t, got.Labels, NoChangesLabelUnverified)
	assert.NotContains(t, got.Extra, "work-retry-after")
	assert.NotContains(t, got.Extra, "work-last-status")
	assert.NotContains(t, got.Extra, "work-no-changes-count")

	events, err := store.Events(beadID)
	require.NoError(t, err)
	for _, ev := range events {
		assert.NotContains(t,
			[]string{"no_changes_unjustified", "execute-bead", "loop-error", "execution-routing-intent", "disruption_detected"},
			ev.Kind,
			"interrupted integration attempt must not write terminal/noise event %q", ev.Kind,
		)
	}

	rawTracker, err := os.ReadFile(filepath.Join(ddxDir, "beads.jsonl"))
	require.NoError(t, err)
	tracker := string(rawTracker)
	for _, forbidden := range []string{
		"no_changes_unjustified",
		"loop-error",
		"execution-routing-intent",
		"work-retry-after",
		"work-last-status",
	} {
		assert.False(t, strings.Contains(tracker, forbidden), "tracker contains %q", forbidden)
	}
}

